import java.util.Scanner;

public class SecureBufferHandling {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Ensure buffer size is at least equal to user input length
        char[] buffer = new char[userInput.length()];

        // Perform bounds checking before copying user input into the buffer
        int lengthToCopy = Math.min(userInput.length(), buffer.length);
        userInput.getChars(0, lengthToCopy, buffer, 0);

        System.out.println("User input copied into buffer successfully!");
    }
}

### Explanation:
취약유형: Buffer Overflow
